/**
 * Notification log model — represents a record of a sent notification.
 *
 * Captures all details needed for notification history tracking:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationChannel, NotificationPriority, NotificationType } from './notification.js';

/**
 * Delivery status of a logged notification.
 */
export type DeliveryStatus = 'sent' | 'failed' | 'skipped';

/**
 * A persistent record of a notification that was processed.
 */
export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  status: DeliveryStatus;
  timestamp: Date;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
  errorMessage?: string;
}

/**
 * Query filter for searching notification history.
 */
export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Provides persistent (in-memory) tracking of all notification delivery
 * attempts with query capabilities by recipient, type, and date range.
 *
 * Integrated into NotificationService via setHistoryService() —
 * every notification that passes through sendNotification() is logged here.
 */

import type {
  NotificationLog,
  NotificationHistoryQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');
  private logs: NotificationLog[] = [];

  /**
   * Record a notification delivery attempt.
   */
  log(
    notificationId: string,
    type: NotificationType,
    payload: NotificationPayload,
    status: DeliveryStatus,
    errorMessage?: string,
  ): NotificationLog {
    const entry: NotificationLog = {
      id: generateLogId(),
      notificationId,
      recipient: payload.recipient,
      channel: payload.channel,
      type,
      subject: payload.subject,
      status,
      timestamp: new Date(),
      priority: payload.priority,
      metadata: payload.metadata,
      errorMessage,
    };

    this.logs.push(entry);
    this.logger.info(
      `Logged notification ${notificationId}: ${status} via ${payload.channel} to ${payload.recipient}`,
    );
    return entry;
  }

  /**
   * Query notification history with optional filters.
   */
  query(filter: NotificationHistoryQuery): NotificationLog[] {
    return this.logs.filter((entry) => {
      if (filter.recipient && entry.recipient !== filter.recipient) return false;
      if (filter.type && entry.type !== filter.type) return false;
      if (filter.channel && entry.channel !== filter.channel) return false;
      if (filter.status && entry.status !== filter.status) return false;
      if (filter.startDate && entry.timestamp < filter.startDate) return false;
      if (filter.endDate && entry.timestamp > filter.endDate) return false;
      return true;
    });
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.query({ recipient });
  }

  /**
   * Get all log entries of a specific notification type.
   */
  getByType(type: NotificationType): NotificationLog[] {
    return this.query({ type });
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.query({ startDate, endDate });
  }

  /**
   * Get all log entries.
   */
  getAll(): NotificationLog[] {
    return [...this.logs];
  }

  /**
   * Get a single log entry by its ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.logs.find((entry) => entry.id === id);
  }

  /**
   * Get the total count of log entries, optionally filtered by status.
   */
  count(status?: DeliveryStatus): number {
    if (status) {
      return this.logs.filter((entry) => entry.status === status).length;
    }
    return this.logs.length;
  }

  /**
   * Clear all log entries (useful for testing).
   */
  clear(): void {
    this.logs = [];
  }
}

