import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
    ...overrides,
  };
}

function makeUserCreatedEvent(): UserCreatedEvent {
  return {
    type: 'user:created',
    user: {
      id: 'user-2',
      name: 'Bob',
      email: 'bob@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };
}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    historyService = new NotificationHistoryService();
    notificationService.setHistoryService(historyService);
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  describe('logging', () => {
    it('should log a notification when sent', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.subject).toContain('Order Confirmation');
      expect(logs[0]!.timestamp).toBeInstanceOf(Date);
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const logs = historyService.getAll();
      expect(logs[0]!.id).toBe('log-0001');
      expect(logs[1]!.id).toBe('log-0002');
    });

    it('should capture notification priority', async () => {
      await eventBus.emit(makeStatusChangedEvent({
        newStatus: 'cancelled',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
      }));

      const logs = historyService.getAll();
      expect(logs[0]!.priority).toBe('high');
    });

    it('should capture metadata', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs[0]!.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
    });

    it('should log failed notifications with error message', async () => {
      const failAdapter: NotificationAdapter = {
        channel: 'email' as const,
        send: async (): Promise<NotificationResult> => {
          throw new Error('Transport failure');
        },
      };
      notificationService.registerAdapter(failAdapter);

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
      expect(logs[0]!.errorMessage).toContain('Transport failure');
    });

    it('should log adapter-reported failures', async () => {
      const failAdapter: NotificationAdapter = {
        channel: 'email' as const,
        send: async (payload: NotificationPayload): Promise<NotificationResult> => ({
          success: false,
          notificationId: 'test',
          channel: payload.channel,
          error: 'Delivery rejected',
        }),
      };
      notificationService.registerAdapter(failAdapter);

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs[0]!.status).toBe('failed');
    });

    it('should log skipped notifications when blocked by preferences', async () => {
      const preferencesService = new PreferencesService();
      preferencesService.updatePreferences('user-1', { emailEnabled: false });
      notificationService.setPreferencesService(preferencesService);

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('skipped');
    });

    it('should log multiple notification types', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeUserCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(2);
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[1]!.type).toBe('user-welcome');
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeUserCreatedEvent());

      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]!.recipient).toBe('alice@example.com');

      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
      expect(bobLogs[0]!.recipient).toBe('bob@example.com');
    });

    it('should return empty array for unknown recipient', () => {
      const logs = historyService.getByRecipient('nobody@example.com');
      expect(logs).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());
      await eventBus.emit(makeUserCreatedEvent());

      const orderLogs = historyService.getByType('order-confirmation');
      expect(orderLogs).toHaveLength(1);

      const statusLogs = historyService.getByType('order-status-update');
      expect(statusLogs).toHaveLength(1);

      const welcomeLogs = historyService.getByType('user-welcome');
      expect(welcomeLogs).toHaveLength(1);
    });
  });

  describe('query by date range', () => {
    it('should return logs within a date range', async () => {
      const before = new Date(Date.now() - 1000);
      await eventBus.emit(makeOrderCreatedEvent());
      const after = new Date(Date.now() + 1000);

      const logs = historyService.getByDateRange(before, after);
      expect(logs).toHaveLength(1);
    });

    it('should exclude logs outside the date range', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const future = new Date(Date.now() + 60000);
      const farFuture = new Date(Date.now() + 120000);
      const logs = historyService.getByDateRange(future, farFuture);
      expect(logs).toHaveLength(0);
    });
  });

  describe('combined query', () => {
    it('should filter by multiple criteria', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());
      await eventBus.emit(makeUserCreatedEvent());

      const logs = historyService.query({
        recipient: 'alice@example.com',
        type: 'order-confirmation',
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('order-confirmation');
    });

    it('should filter by status', async () => {
      const failAdapter: NotificationAdapter = {
        channel: 'email' as const,
        send: async (): Promise<NotificationResult> => {
          throw new Error('fail');
        },
      };
      notificationService.registerAdapter(failAdapter);

      await eventBus.emit(makeOrderCreatedEvent());

      // Remove adapter so next one succeeds (in-memory fallback)
      notificationService.registerAdapter({
        channel: 'email' as const,
        send: async (payload: NotificationPayload): Promise<NotificationResult> => ({
          success: true,
          notificationId: 'ok',
          channel: payload.channel,
        }),
      });
      await eventBus.emit(makeUserCreatedEvent());

      const failedLogs = historyService.query({ status: 'failed' });
      expect(failedLogs).toHaveLength(1);

      const sentLogs = historyService.query({ status: 'sent' });
      expect(sentLogs).toHaveLength(1);
    });

    it('should filter by channel', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);

      const smsLogs = historyService.query({ channel: 'sms' });
      expect(smsLogs).toHaveLength(0);
    });
  });

  describe('getById', () => {
    it('should return a specific log entry', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const log = historyService.getById('log-0001');
      expect(log).toBeDefined();
      expect(log!.type).toBe('order-confirmation');
    });

    it('should return undefined for unknown ID', () => {
      expect(historyService.getById('log-9999')).toBeUndefined();
    });
  });

  describe('count', () => {
    it('should count all log entries', async () => {
      expect(historyService.count()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeUserCreatedEvent());
      expect(historyService.count()).toBe(2);
    });

    it('should count by status', async () => {
      const failAdapter: NotificationAdapter = {
        channel: 'email' as const,
        send: async (): Promise<NotificationResult> => {
          throw new Error('fail');
        },
      };
      notificationService.registerAdapter(failAdapter);
      await eventBus.emit(makeOrderCreatedEvent());

      // Remove failing adapter
      notificationService.registerAdapter({
        channel: 'email' as const,
        send: async (payload: NotificationPayload): Promise<NotificationResult> => ({
          success: true,
          notificationId: 'ok',
          channel: payload.channel,
        }),
      });
      await eventBus.emit(makeUserCreatedEvent());

      expect(historyService.count('failed')).toBe(1);
      expect(historyService.count('sent')).toBe(1);
    });
  });

  describe('clear', () => {
    it('should remove all log entries', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      expect(historyService.count()).toBe(1);

      historyService.clear();
      expect(historyService.count()).toBe(0);
      expect(historyService.getAll()).toHaveLength(0);
    });
  });
});
